const express = require('express');
const { getProjects, createProject } = require('./service');
const router = express.Router();

router.get('/', (req, res) => {
  const projects = getProjects();
  res.json({ projects });
});

router.post('/', (req, res) => {
  const { name } = req.body;
  if (!name) {
    return sendError(res, 400, 'INVALID_NAME', 'Name is required');
  }
  const project = createProject(name);
  res.status(201).json({ project });
});

module.exports = router;

const { randomUUID } = require('node:crypto');
let projects = {};

function getProjects() {
  return Object.values(projects);
}

function createProject(name) {
  const id = randomUUID();
  const project = { id, name, tasks: {}, members: {} };
  projects[id] = project;
  return project;
}

module.exports = { getProjects, createProject };

const express = require('express');
const { getTasks, createTask, updateTaskStatus } = require('./service');
const router = express.Router();

router.get('/', (req, res) => {
  const projectId = req.projectId;
  const status = req.query.status;
  const tasks = getTasks(projectId, status);
  res.json({ tasks });
});

router.post('/', (req, res) => {
  const projectId = req.projectId;
  const { title } = req.body;
  if (!title) {
    return sendError(res, 400, 'INVALID_TITLE', 'Title is required');
  }
  const task = createTask(projectId, title);
  res.status(201).json({ task });
});

router.patch('/:taskId', (req, res) => {
  const projectId = req.projectId;
  const { taskId } = req.params;
  const { status } = req.body;
  if (!status || !['todo', 'done'].includes(status)) {
    return sendError(res, 400, 'INVALID_STATUS', 'Status must be either todo or done');
  }
  const task = updateTaskStatus(projectId, taskId, status);
  if (!task) {
    return sendError(res, 404, 'TASK_NOT_FOUND', 'Task not found');
  }
  res.json({ task });
});

module.exports = router;

const { randomUUID } = require('node:crypto');
const { projects } = require('../projects/service');

function getTasks(projectId, status) {
  const project = projects[projectId];
  if (!project) return [];
  return Object.values(project.tasks).filter(task => !status || task.status === status);
}

function createTask(projectId, title) {
  const project = projects[projectId];
  if (!project) return null;
  const id = randomUUID();
  const task = { id, title, status: 'todo' };
  project.tasks[id] = task;
  return task;
}

function updateTaskStatus(projectId, taskId, status) {
  const project = projects[projectId];
  if (!project || !project.tasks[taskId]) return null;
  project.tasks[taskId].status = status;
  return project.tasks[taskId];
}

module.exports = { getTasks, createTask, updateTaskStatus };

const express = require('express');
const { getComments, createComment } = require('./service');
const router = express.Router();

router.get('/', (req, res) => {
  const projectId = req.projectId;
  const taskId = req.taskId;
  const comments = getComments(projectId, taskId);
  res.json({ comments });
});

router.post('/', (req, res) => {
  const projectId = req.projectId;
  const taskId = req.taskId;
  const { message } = req.body;
  if (!message) {
    return sendError(res, 400, 'INVALID_MESSAGE', 'Message is required');
  }
  const comment = createComment(projectId, taskId, message);
  res.status(201).json({ comment });
});

module.exports = router;

const { randomUUID } = require('node:crypto');
const { projects } = require('../projects/service');

function getComments(projectId, taskId) {
  const project = projects[projectId];
  if (!project || !project.tasks[taskId]) return [];
  return Object.values(project.tasks[taskId].comments || {});
}

function createComment(projectId, taskId, message) {
  const project = projects[projectId];
  if (!project || !project.tasks[taskId]) return null;
  const id = randomUUID();
  const comment = { id, message };
  if (!project.tasks[taskId].comments) {
    project.tasks[taskId].comments = {};
  }
  project.tasks[taskId].comments[id] = comment;
  return comment;
}

module.exports = { getComments, createComment };

const express = require('express');
const { getMembers, addMember } = require('./service');
const router = express.Router();

router.get('/', (req, res) => {
  const projectId = req.projectId;
  const members = getMembers(projectId);
  res.json({ members });
});

router.post('/', (req, res) => {
  const projectId = req.projectId;
  const { userId, role } = req.body;
  if (!userId || !role) {
    return sendError(res, 400, 'INVALID_INPUT', 'UserId and role are required');
  }
  const member = addMember(projectId, userId, role);
  res.status(201).json({ member });
});

module.exports = router;

const { projects } = require('../projects/service');

function getMembers(projectId) {
  const project = projects[projectId];
  if (!project) return [];
  return Object.values(project.members);
}

function addMember(projectId, userId, role) {
  const project = projects[projectId];
  if (!project) return null;
  const member = { userId, role };
  project.members[userId] = member;
  return member;
}

module.exports = { getMembers, addMember };

const express = require('express');
const projectsRouter = require('./modules/projects/routes');
const membersRouter = require('./modules/members/routes');
const tasksRouter = require('./modules/tasks/routes');
const commentsRouter = require('./modules/comments/routes');
const { sendError } = require('./lib/errors');

const app = express();
app.use(express.json());

app.get('/health', (req, res) => {
  res.json({ ok: true });
});

app.use('/projects/:projectId/members', (req, res, next) => {
  req.projectId = req.params.projectId;
  next();
}, membersRouter);

app.use('/projects/:projectId/tasks', (req, res, next) => {
  req.projectId = req.params.projectId;
  next();
}, tasksRouter);

app.use('/projects/:projectId/tasks/:taskId/comments', (req, res, next) => {
  req.projectId = req.params.projectId;
  req.taskId = req.params.taskId;
  next();
}, commentsRouter);

app.use('/projects', projectsRouter);

app.use((err, req, res, next) => {
  console.error(err.stack);
  sendError(res, 500, 'INTERNAL_ERROR', 'Internal Server Error');
});

module.exports = app;

function sendError(res, status, code, message) {
  res.status(status).json({ error: { code, message } });
}

module.exports = { sendError };
